package com.keyrico.keyrisdk

import android.content.Context
import android.graphics.BitmapFactory
import android.util.Base64
import android.util.Log
import android.webkit.JavascriptInterface
import android.webkit.WebView
import androidx.core.net.toUri
import androidx.test.platform.app.InstrumentationRegistry
import com.google.mlkit.vision.barcode.BarcodeScannerOptions
import com.google.mlkit.vision.barcode.BarcodeScanning
import com.google.mlkit.vision.barcode.common.Barcode
import com.google.mlkit.vision.common.InputImage
import kotlinx.coroutines.delay
import kotlinx.coroutines.runBlocking
import org.junit.Assert
import org.junit.Before
import org.junit.Test
import org.junit.runner.RunWith
import org.junit.runners.JUnit4


@RunWith(JUnit4::class)
class ExampleAppInstrumentedTest {

    private var scannedData: String? = null

    private lateinit var context: Context
    private lateinit var keyriSdk: KeyriSdk

    @Before
    fun setup() {
        context = InstrumentationRegistry.getInstrumentation().context
        keyriSdk = KeyriSdk(
            context,
            "BOenio0DXyG31mAgUCwhdslelckmxzM7nNOyWAjkuo7skr1FhP7m2L8PaSRgIEH5ja9p+CwEIIKGqR4Hx5Ezam4=",
            "misc.keyri.com"
        )
    }

    // TODO 1. Remove this BASE64 String
    // TODO 2. Try to parse QR code

    private val testImage =
        ""

    @Test
    fun `1_getScannedData`() = runBlocking {


        val vw = WebView(context)

        vw.loadUrl("http://www.example.com")

        vw.settings.javaScriptEnabled = true

        vw.addJavascriptInterface(this, "android")
        vw.loadUrl("javascript:android.onData('Hey!')")

        val decodedString: ByteArray = Base64.decode(testImage, Base64.DEFAULT)
        val bitmap = BitmapFactory.decodeByteArray(decodedString, 0, decodedString.size)

        val options = BarcodeScannerOptions.Builder()
            .setBarcodeFormats(Barcode.FORMAT_QR_CODE, Barcode.FORMAT_AZTEC)
            .build()

        val image = InputImage.fromBitmap(bitmap, 0)

        BarcodeScanning.getClient(options)
            .process(image)
            .addOnSuccessListener { barcodes ->
                scannedData = barcodes.firstOrNull()?.displayValue

                Log.d("Keyri", "SCANNED DATA: $scannedData")
            }

        delay(10_000L)

        val sessionId =
            requireNotNull(
                scannedData?.toUri()?.getQueryParameters("sessionId".lowercase())?.firstOrNull()
            )

        Log.d("Keyri", "SESSION ID: $sessionId")

        val session = keyriSdk.handleSessionId(sessionId)

        Assert.assertEquals(session.widgetOrigin, "misc.keyri.com")

        keyriSdk.challengeSession(
            "some-public-user-id",
            sessionId,
            "Secure custom",
            "Public custom",
        )

        delay(10_000L)
    }

    @JavascriptInterface
    fun onData(value: String?) {
        Log.d("JS RECEIVED", "data: $value")
    }
}
